        node: ASTNode,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
        autoCorrect: Boolean,
    ) {
        val psi = node.psi
        require(psi is KtClass)

        node
            .takeIf { psi.isEnum() }
            ?.findChildByType(ElementType.CLASS_BODY)
            ?.takeIf {
                // Only process if there is at least one enum entry
                it.children().any { child -> child.psi is KtEnumEntry }
            }
            ?.takeUnless {
                // Do nothing when last two entries are on same line as no trailing comma should be inserted
                it.lastTwoEnumEntriesAreOnSameLine()
            }?.let { classBody ->
                val nodeAfterTrailingCommaPosition = classBody.findNodeAfterTrailingCommaPosition()
                node.reportAndCorrectTrailingCommaNodeBefore(
                    inspectNode = nodeAfterTrailingCommaPosition,
                    isTrailingCommaAllowed = node.isTrailingCommaAllowed(),
                    autoCorrect = autoCorrect,
                    emit = emit,
                )
            }
    }"}

{"file_path": "/project/ktlint-ruleset-standard/src/test/kotlin/com/pinterest/ktlint/ruleset/standard/rules/TrailingCommaOnDeclarationSiteRuleEmptyEnumTest.kt", "content": "package com.pinterest.ktlint.ruleset.standard.rules

import com.pinterest.ktlint.rule.engine.core.api.RuleProvider
import com.pinterest.ktlint.ruleset.standard.rules.TrailingCommaOnDeclarationSiteRule.Companion.TRAILING_COMMA_ON_DECLARATION_SITE_PROPERTY
import com.pinterest.ktlint.test.KtLintAssertThat
import org.junit.jupiter.api.Test

/**
 * Test for empty enum classes to ensure TrailingCommaOnDeclarationSiteRule
 * doesn't crash with NoSuchElementException.
 *
 * Issue: https://github.com/pinterest/ktlint/issues/<issue_number>
 */
class TrailingCommaOnDeclarationSiteRuleEmptyEnumTest {
    private val trailingCommaOnDeclarationSiteRuleAssertThat =
        KtLintAssertThat.assertThatRule(
            provider = { TrailingCommaOnDeclarationSiteRule() },
            additionalRuleProviders = setOf(
                // WrappingRule must be loaded in order to run TrailingCommaOnCallSiteRule
                RuleProvider { WrappingRule() },
                // Apply the IndentationRule always as additional rule, so that the formattedCode in the unit test looks
                // correct.
                RuleProvider { IndentationRule() },
            ),
        )

    @Test
    fun `Given an empty enum class then no error is raised`() {
        val code =
            """
            enum class EmptyEnum {
            }
            """.trimIndent()
        trailingCommaOnDeclarationSiteRuleAssertThat(code)
            .withEditorConfigOverride(TRAILING_COMMA_ON_DECLARATION_SITE_PROPERTY to true)
            .hasNoLintViolations()
    }

    @Test
    fun `Given an empty enum class with trailing comma property set to false then no error is raised`() {
        val code =
            """
            enum class EmptyEnum {
            }
            """.trimIndent()
        trailingCommaOnDeclarationSiteRuleAssertThat(code)
            .withEditorConfigOverride(TRAILING_COMMA_ON_DECLARATION_SITE_PROPERTY to false)
            .hasNoLintViolations()
    }

    @Test
    fun `Given an empty enum class with whitespace then no error is raised`() {
        val code =
            """
            enum class EmptyEnum {

            }
            """.trimIndent()
        trailingCommaOnDeclarationSiteRuleAssertThat(code)
            .withEditorConfigOverride(TRAILING_COMMA_ON_DECLARATION_SITE_PROPERTY to true)
            .hasNoLintViolations()
    }

    @Test
    fun `Given an empty enum class with a companion object then no error is raised`() {
        val code =
            """
            enum class EmptyEnum {
                companion object {
                    const val TEST = "test"
                }
            }
            """.trimIndent()
        trailingCommaOnDeclarationSiteRuleAssertThat(code)
            .withEditorConfigOverride(TRAILING_COMMA_ON_DECLARATION_SITE_PROPERTY to true)
            .hasNoLintViolations()
    }

    @Test
    fun `Given an empty enum class with a semicolon and method then no error is raised`() {
        val code =
            """
            enum class EmptyEnum {
                ;
                fun test() {
                    println("test")
                }
            }
            """.trimIndent()
        trailingCommaOnDeclarationSiteRuleAssertThat(code)
            .withEditorConfigOverride(TRAILING_COMMA_ON_DECLARATION_SITE_PROPERTY to true)
            .hasNoLintViolations()
    }

    @Test
    fun `Given an enum class with single entry then trailing comma rules work as expected`() {
        val code =
            """
            enum class SingleEntry {
                ONE
            }
            """.trimIndent()
        val formattedCode =
            """
            enum class SingleEntry {
                ONE,
            }
            """.trimIndent()
        trailingCommaOnDeclarationSiteRuleAssertThat(code)
            .withEditorConfigOverride(TRAILING_COMMA_ON_DECLARATION_SITE_PROPERTY to true)
            .hasLintViolation(2, 4, "Missing trailing comma before \"}\"")
            .isFormattedAs(formattedCode)
    }
}
