import com.pinterest.ktlint.ruleset.standard.rules.TrailingCommaOnDeclarationSiteRule.Companion.TRAILING_COMMA_ON_DECLARATION_SITE_PROPERTY
import com.pinterest.ktlint.test.KtLintAssertThat
import org.junit.jupiter.api.Test

/**
 * Integration test to verify the fix for the issue where ktlint raises error
 * when there is an empty enum class.
 *
 * This reproduces the exact scenario from the reported issue:
 * https://github.com/pinterest/ktlint/issues/<issue_number>
 *
 * Before the fix, this would throw:
 * java.util.NoSuchElementException: Sequence contains no element matching the predicate.
 */
class TrailingCommaOnDeclarationSiteRuleIssueTest {
    private val trailingCommaOnDeclarationSiteRuleAssertThat =
        KtLintAssertThat.assertThatRule(
            provider = { TrailingCommaOnDeclarationSiteRule() },
            additionalRuleProviders = setOf(
                // WrappingRule must be loaded in order to run TrailingCommaOnCallSiteRule
                RuleProvider { WrappingRule() },
                // Apply the IndentationRule always as additional rule, so that the formattedCode in the unit test looks
                // correct.
                RuleProvider { IndentationRule() },
            ),
        )

    @Test
    fun `Issue - Empty enum class should not cause NoSuchElementException`() {
        val code =
            """
            package com.example.myapplication.hostconfig

            import androidx.compose.ui.tooling.preview.Preview

            /**
             * API configuration
             */
            interface HostConfig {
                val host: String
                val protocol: String
            }

            /**
             * Test API configuration
             */
            class TestHostConfig : HostConfig {
                override val host: String = "testhost"
                override val protocol: String = "https"
            }

            enum class TestView {
            }

            @Preview
            fun PreviewTest() {
                // Empty preview
            }
            """.trimIndent()
        // This should not throw NoSuchElementException
        trailingCommaOnDeclarationSiteRuleAssertThat(code)
            .withEditorConfigOverride(TRAILING_COMMA_ON_DECLARATION_SITE_PROPERTY to true)
            .hasNoLintViolations()
    }

    @Test
    fun `Issue - Empty enum class with trailing comma disabled should not cause NoSuchElementException`() {
        val code =
            """
            enum class TestView {
            }
            """.trimIndent()
        // This should not throw NoSuchElementException
        trailingCommaOnDeclarationSiteRuleAssertThat(code)
            .withEditorConfigOverride(TRAILING_COMMA_ON_DECLARATION_SITE_PROPERTY to false)
            .hasNoLintViolations()
    }

    @Test
    fun `Issue - Multiple empty enum classes should not cause NoSuchElementException`() {
        val code =
            """
            enum class EmptyEnum1 {
            }

            enum class EmptyEnum2 {
            }

            enum class EmptyEnum3 {
            }
            """.trimIndent()
        // This should not throw NoSuchElementException
        trailingCommaOnDeclarationSiteRuleAssertThat(code)
            .withEditorConfigOverride(TRAILING_COMMA_ON_DECLARATION_SITE_PROPERTY to true)
            .hasNoLintViolations()
    }
}
